class Solution {
    public int countKReducibleNumbers(String s, int k) {
        int n = Integer.parseInt(s, 2);
        int res = 0;
        for (int i = 1; i < n; i++) {
            int x = i;
            int ops = 0;
            while (x > 1 && ops <= k) {
                x = Integer.bitCount(x);
                ops++;
            }
            if (x == 1) res++;
        }
        return res % (1000000007);
    }
}
```
